function getMailServerFrom(input) {
    var oReq = new XMLHttpRequest();
    oReq.open('PROPFIND', ajaxRequest_baseUrl + '/getServerFromMail', true);
    oReq.setRequestHeader("Content-Type", "application/json");
    oReq.setRequestHeader("requesttoken", oc_requesttoken);
    oReq.onload = function(e){
        if (this.status == 200) {
            input.value = JSON.parse(this.response)['mail'];
        }else{
            ajaxRequest_showError(this.response);
        }
    };
    oReq.send();
}

