function addShareUser(email){
    var myData = {
        email: email
    };

    fetch(ajaxRequest_baseUrl + '/addShareUser', {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
            'requesttoken': OC.requestToken
        },
        body: JSON.stringify(myData)
    })
    .then(response => {
        if (response.status >= 200 && response.status < 300) {
            window.location.reload();
        } else {
            return response.json();
        }
    })
    .then(data => {
        showMessage(ajaxRequest_t('gestion', 'Information : ') + data.data);
    })
    
};

function delShareUser(uid){
    var myData = {
        uid: uid
    };

    fetch(ajaxRequest_baseUrl + '/delShareUser', {
        method: 'DELETE',
        headers: {
            'Content-Type': 'application/json',
            'requesttoken': OC.requestToken
        },
        body: JSON.stringify(myData)
    })
    .then(response => {
        if (response.status >= 200 && response.status < 300) {
            window.location.reload();
        } else {
            return response.json();
        }
    })
    .then(data => {
        ajaxRequest_showError(ajaxRequest_t('gestion', 'Information : ') + data.data);
    })
};
